241→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
242→  const nav = useNavigationStack<NavViewData>('Raycast');
243→  const { push } = nav;
244→
245→  const viewType = nav.currentEntry?.data.type ?? 'root';
246→
247→  const searchFilterSections: SearchDropdownSection[] = useMemo(
248→    () => [
249→      {
