@use '../../styles/tokens' as *;

$quick-look-width: 620px;
$quick-look-max-height: 460px;
$quick-look-header-height: 44px;

.quick-look__backdrop {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: $backdrop-overlay;
  backdrop-filter: blur($backdrop-blur);
  -webkit-backdrop-filter: blur($backdrop-blur);
  z-index: $z-quick-look;
  border-radius: $radius-window;
  animation: quick-look-backdrop-enter $transition-normal ease-out both;

  &--exiting {
    animation: quick-look-backdrop-exit $transition-normal ease-in both;
  }
}

.quick-look__card {
  display: flex;
  flex-direction: column;
  width: $quick-look-width;
  max-width: calc(100% - #{$space-8});
  max-height: $quick-look-max-height;
  background: $color-surface;
  border: 1px solid $border-100;
  border-radius: $radius-lg;
  box-shadow: $shadow-popover;
  overflow: hidden;
  animation: quick-look-card-enter $transition-normal ease-out both;

  &--exiting {
    animation: quick-look-card-exit $transition-normal ease-in both;
  }
}

.quick-look__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: $quick-look-header-height;
  padding: 0 $space-4;
  border-bottom: 1px solid $border-100;
  flex-shrink: 0;
}

.quick-look__title {
  margin: 0;
  font-size: $font-sm;
  font-weight: $font-weight-medium;
  color: $text-600;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.quick-look__close {
  display: flex;
  align-items: center;
  justify-content: center;
  width: $space-5;
  height: $space-5;
  padding: 0;
  border: none;
  border-radius: $radius-sm;
  background: transparent;
  color: $text-400;
  cursor: pointer;
  transition: color $transition-fast ease, background-color $transition-fast ease;

  &:hover {
    color: $color-text-primary;
    background: $border-100;
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: -2px;
  }
}

.quick-look__body {
  flex: 1;
  overflow-y: auto;
  min-height: 0;

  .detail {
    border-left: none;
  }
}

@keyframes quick-look-backdrop-enter {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes quick-look-backdrop-exit {
  from {
    opacity: 1;
  }
  to {
    opacity: 0;
  }
}

@keyframes quick-look-card-enter {
  from {
    opacity: 0;
    transform: scale(0.92);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes quick-look-card-exit {
  from {
    opacity: 1;
    transform: scale(1);
  }
  to {
    opacity: 0;
    transform: scale(0.92);
  }
}

