            dropdown={
              viewType === 'root' ? (
                <SearchDropdown
                  sections={searchFilterSections}
                  value={filterValue}
                  onChange={handleFilterChange}
                />
              ) : undefined
            }
          />
        )}
        {isFullView && nav.currentEntry ? (
          <div
            key={nav.navKey}
            className={`command-palette__nav-view${navDirectionClass}`}
