          </div>
        ) : nav.currentEntry ? (
          <div
            key={nav.navKey}
            className={`command-palette__nav-view${navDirectionClass}`}
          >
            <div className="command-palette__body">
              <div className="command-palette__list-container">
                {renderCurrentView()}
              </div>
            </div>
          </div>
